import React, { useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import { useAndesContext } from '@andes/context';
import warning from '@andes/common/build/utils/warning';
import { WARNING_CSRF } from './constants/warning';

/**
 * Form allows the user to input data, and is a system defined by the
 * relationship between several form controls and their criteria of use.
 *
 * @type {typeof import('../index').Form}
 */
const Form = ({
  children,
  ref,
  ...props
}) => {
  const { csrfToken } = useAndesContext();

  const [metaCsrfToken, setMetaCsrfToken] = useState(
    /** @type {string | null} */ (null),
  );
  const inputValue = csrfToken || metaCsrfToken;

  useEffect(() => {
    if (!csrfToken) {
      const metaTag = document.querySelector('meta[name=csrf-token]');
      if (metaTag) {
        setMetaCsrfToken(metaTag.getAttribute('content'));
      }
    }
  }, [csrfToken]);

  warning(csrfToken, WARNING_CSRF);

  return (
    <form {...props} ref={ref}>
      {(inputValue) && (<input type="hidden" name="_csrf" value={inputValue} />)}
      {children}
    </form>
  );
};

Form.displayName = 'Form';

Form.propTypes = {
  children: PropTypes.node.isRequired,
};

export default Form;
